namespace InventoryFlow.Domain.Common;

/// <summary>
/// Represents a domain entity with an identity.
/// </summary>
/// <typeparam name="TId">The type used to identify the entity.</typeparam>
public abstract class Entity<TId>
    where TId : notnull
{
    /// <summary>
    /// Initializes a new instance of the <see cref="Entity{TId}"/> class.
    /// </summary>
    /// <param name="id">The entity identifier.</param>
    protected Entity(TId id)
    {
        Id = id;
    }

    /// <summary>
    /// Gets the entity identifier.
    /// </summary>
    public TId Id { get; protected set; }
}
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Identity;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace InventoryFlow.Infrastructure.Persistence.Configurations;

/// <summary>
/// Configures persistence for <see cref="RefreshToken"/> entities.
/// </summary>
public sealed class RefreshTokenConfiguration : IEntityTypeConfiguration<RefreshToken>
{
    /// <inheritdoc />
    public void Configure(EntityTypeBuilder<RefreshToken> builder)
    {
        builder.ToTable("RefreshTokens");
        builder.HasKey(token => token.Id);

        builder.Property(token => token.FamilyId)
            .IsRequired();

        builder.Property(token => token.TokenHash)
            .HasMaxLength(128)
            .IsRequired();

        builder.Property(token => token.ExpiresAtUtc)
            .IsRequired();

        builder.HasIndex(token => token.TokenHash)
            .IsUnique();

        builder.HasIndex(token => new { token.UserId, token.ExpiresAtUtc });

        builder.HasIndex(token => token.FamilyId);

        builder.HasOne<ApplicationUser>()
            .WithMany()
            .HasForeignKey(token => token.UserId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Identity;
using Microsoft.AspNetCore.DataProtection.EntityFrameworkCore;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Persistence;

/// <summary>
/// Provides SQL Server persistence for Identity and Inventory Flow data.
/// </summary>
/// <param name="options">The options used to configure the context.</param>
public sealed class ApplicationDbContext(
    DbContextOptions<ApplicationDbContext> options)
    : IdentityDbContext<ApplicationUser, IdentityRole<Guid>, Guid>(options), IDataProtectionKeyContext
{
    /// <summary>
    /// Gets the issued refresh tokens.
    /// </summary>
    public DbSet<RefreshToken> RefreshTokens => Set<RefreshToken>();

    /// <summary>
    /// Gets the shared data-protection keys used by Identity token providers.
    /// </summary>
    public DbSet<DataProtectionKey> DataProtectionKeys => Set<DataProtectionKey>();

    /// <inheritdoc />
    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.ApplyConfigurationsFromAssembly(typeof(ApplicationDbContext).Assembly);
    }
}
export type AuthenticatedUser = {
  id: string
  email: string
  displayName: string
}
export type AuthenticationResponse = {
  accessToken: string
  accessTokenExpiresAtUtc: string
  user: AuthenticatedUser
}
import { create } from "zustand"
import type {
  AuthenticationResponse,
  AuthenticatedUser,
} from "@/features/auth/types"

type AuthState = {
  accessToken: string | null
  user: AuthenticatedUser | null
  isRestoring: boolean
  setSession: (session: AuthenticationResponse) => void
  clearSession: () => void
  finishRestoring: () => void
}
export const useAuthStore = create<AuthState>((set) => ({
  accessToken: null,
  user: null,
  isRestoring: true,
  setSession: (session) =>
    set({ accessToken: session.accessToken, user: session.user }),
  clearSession: () => set({ accessToken: null, user: null }),
  finishRestoring: () => set({ isRestoring: false }),
}))

